CREATE TABLE IF NOT EXISTS public.blogs (id uuid NOT NULL, title text NOT NULL, content text NOT NULL, image_url text, video_url text, author text, created_at timestamp with time zone, updated_at timestamp with time zone);
CREATE TABLE IF NOT EXISTS public.conversations (id uuid NOT NULL, product_name text NOT NULL, product_price numeric NOT NULL, buyer_id uuid, seller_id uuid, escrow_step integer, status text, created_at timestamp with time zone, updated_at timestamp with time zone, last_message text, product_id uuid, admin_id uuid);
CREATE TABLE IF NOT EXISTS public.deals (id uuid NOT NULL, user_id uuid, status text, amount numeric, created_at timestamp with time zone, title text, price numeric, buyer_id uuid, seller_id uuid, category text);
CREATE TABLE IF NOT EXISTS public.disputes (id uuid NOT NULL, conversation_id uuid NOT NULL, buyer_id uuid, seller_id uuid, reason text NOT NULL, description text, status text, created_at timestamp with time zone, resolved_at timestamp with time zone, ai_result jsonb);
CREATE TABLE IF NOT EXISTS public.messages (id uuid NOT NULL, conversation_id uuid, sender_id uuid, content text NOT NULL, type text, created_at timestamp with time zone, is_read boolean, reply_to_id uuid, file_name text);
CREATE TABLE IF NOT EXISTS public.notifications (id uuid NOT NULL, user_id uuid, title text NOT NULL, message text NOT NULL, icon text, is_read boolean, created_at timestamp without time zone, type text);
CREATE TABLE IF NOT EXISTS public.profiles (id uuid NOT NULL, username text, email text, phone text, role text NOT NULL, country text, country_code text, country_flag text, ip_address text, ip_meta jsonb, kyc_status text, created_at timestamp with time zone, updated_at timestamp with time zone, telegram_chat_id text, balance numeric, accounts_sold integer, total_earnings numeric, total_deals integer, is_active boolean, full_name text, about text, last_ip text, last_device text, telegram_alerts boolean, show_online boolean, show_last_seen boolean, public_profile boolean, suspended_until timestamp without time zone, welcome_sent boolean, avatar_url text, last_seen timestamp with time zone, trust_score numeric, total_reviews integer, last_avatar_update timestamp with time zone, last_name_update timestamp with time zone, is_official_ban boolean, security_pin text, onesignal_id text, push_notifications_enabled boolean, following jsonb, followers jsonb);
CREATE TABLE IF NOT EXISTS public.revenue (id uuid NOT NULL, user_id uuid, type text NOT NULL, amount numeric NOT NULL, order_id uuid, notes text, created_at timestamp with time zone NOT NULL);
CREATE TABLE IF NOT EXISTS public.reviews (id uuid NOT NULL, created_at timestamp with time zone, conversation_id uuid, reviewer_id uuid, seller_id uuid, rating integer, comment text);
CREATE TABLE IF NOT EXISTS public.support_tickets (id uuid NOT NULL, user_id uuid NOT NULL, subject text NOT NULL, status text NOT NULL, assigned_admin text, attachment_url text, created_at timestamp with time zone, message text, ticket_number text);
CREATE TABLE IF NOT EXISTS public.telegram_links (id uuid NOT NULL, chat_id text, email text NOT NULL, code text NOT NULL, verified boolean, created_at timestamp with time zone, expires_at timestamp with time zone);
CREATE TABLE IF NOT EXISTS public.ticket_messages (id uuid NOT NULL, ticket_id uuid, sender text NOT NULL, sender_id uuid NOT NULL, message text NOT NULL, created_at timestamp with time zone, attachment_url text);
CREATE TABLE IF NOT EXISTS public.user_verifications (id uuid NOT NULL, user_id uuid NOT NULL, email text, telegram text, payment_reference text NOT NULL, amount numeric NOT NULL, status text, created_at timestamp with time zone, updated_at timestamp with time zone, dispatch_status text);
CREATE TABLE IF NOT EXISTS public.verifications (id uuid NOT NULL, user_id uuid NOT NULL, data jsonb NOT NULL, screenshot_url text, status text, submitted_at timestamp with time zone, verified_at timestamp with time zone);
CREATE TABLE IF NOT EXISTS public.wallet (id uuid NOT NULL, user_id uuid NOT NULL, type text NOT NULL, amount numeric NOT NULL, note text, status text, reference text, created_at timestamp with time zone);
CREATE TABLE IF NOT EXISTS public.withdrawals (id uuid NOT NULL, user_id uuid, amount numeric NOT NULL, method text NOT NULL, details jsonb NOT NULL, status text, created_at timestamp with time zone, processed_at timestamp with time zone, bank_name text, account_name text, bank_code text, account_number text, transaction_id uuid);
